import java.util.ArrayList;
import java.util.List;
import java.util.PriorityQueue;

public class Solution {
    public static long solve(long[][] grid, long k) {
        int m = grid.length;
        int n = grid[0].length;

        List<int[]>[][] teleport = new ArrayList[m][n];
        for (int i = 0; i < m; i++) {
            teleport[i] = new ArrayList[n];
            for (int j = 0; j < n; j++) {
                teleport[i][j] = new ArrayList<>();
                long val = grid[i][j];
                for (int x = 0; x < m; x++) {
                    for (int y = 0; y < n; y++) {
                        if (grid[x][y] <= val) {
                            teleport[i][j].add(new int[]{x, y});
                        }
                    }
                }
            }
        }

        long[][][] dist = new long[m][n][k+1];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                for (int t = 0; t <= k; t++) {
                    dist[i][j][t] = Long.MAX_VALUE;
                }
            }
        }
        dist[0][0][0] = 0;

        PriorityQueue<long[]> heap = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
        heap.add(new long[]{0, 0, 0, 0});

        while (!heap.isEmpty()) {
            long[] current = heap.poll();
            long currentCost = current[0];
            int i = current[1];
            int j = current[2];
            int t = current[3];

            if (i == m - 1 && j == n - 1) {
                return currentCost;
            }

            if (currentCost > dist[i][j][t]) {
                continue;
            }

            // Regular moves
            if (j + 1 < n) {
                long newCost = currentCost + grid[i][j+1];
                if (newCost < dist[i][j+1][t]) {
                    dist[i][j+1][t] = newCost;
                    heap.add(new long[]{newCost, i, j+1, t});
                }
            }
            if (i + 1 < m) {
                long newCost = currentCost + grid[i+1][j];
                if (newCost < dist[i+1][j][t]) {
                    dist[i+1][j][t] = newCost;
                    heap.add(new long[]{newCost, i+1, j, t});
                }
            }

            // Teleportation
            if (t < k) {
                for (int[] coord : teleport[i][j]) {
                    int x = coord[0];
                    int y = coord[1];
                    long newT = t + 1;
                    long newCost = currentCost;
                    if (newCost < dist[x][y][newT]) {
                        dist[x][y][newT] = newCost;
                        heap.add(new long[]{newCost, x, y, newT});
                    }
                }
            }
        }

        return -1;
    }
}
