            long[] current = pq.poll();
            long current_cost = current[0];
            int i = current[1];
            int j = current[2];
            int t = current[3];

            // Check if destination
            if (i == m - 1 && j == n - 1) {
                return current_cost;
            }

            // Check if current cost is larger than stored
            if (current_cost > dist[i][j][t]) {
                continue;
            }

            // Regular moves
