            if (j + 1 < n) {
                long new_cost = current_cost + grid[i][j + 1];
                if (new_cost < dist[i][j + 1][t]) {
                    dist[i][j + 1][t] = new_cost;
                    pq.add(new long[]{new_cost, i, j + 1, t});
                }
            }
            // Down
            if (i + 1 < m) {
                long new_cost = current_cost + grid[i + 1][j];
                if (new_cost < dist[i + 1][j][t]) {
                    dist[i + 1][j][t] = new_cost;
                    pq.add(new long[]{new_cost, i + 1, j, t});
                }
            }

            // Teleport
            if (t < k) {
                for (int[] xy : teleport.get(i).get(j)) {
                    int x = xy[0];
                    int y = xy[1];
                    long new_t = t + 1;
                    if (current_cost < dist[x][y][new_t]) {
                        dist[x][y][new_t] = current_cost;
                        pq.add(new long[]{current_cost, x, y, new_t});
                    }
                }
            }
        }

        return -1;
    }
}
