public static long solve(long[][] grid, long k) {
    int m = grid.length;
    int n = grid[0].length;
    // Precompute teleport lists
    List<List<int[]>> teleport = new ArrayList<>();
    for (int i = 0; i < m; i++) {
        teleport.add(new ArrayList<>());
        for (int j = 0; j < n; j++) {
            List<int[]> list = new ArrayList<>();
            long val = grid[i][j];
            for (int x = 0; x < m; x++) {
                for (int y = 0; y < n; y++) {
                    if (grid[x][y] <= val) {
                        list.add(new int[]{x, y});
                    }
                }
            }
            teleport.get(i).add(list);
        }
    }

    // Initialize distance array
    long[][][] dist = new long[m][n][k+1];
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            for (int t = 0; t <= k; t++) {
                dist[i][j][t] = Long.MAX_VALUE;
            }
        }
    }
    dist[0][0][0] = 0;

    // Priority queue: [cost, i, j, t]
    PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
    pq.offer(new long[]{0, 0, 0, 0});

    while (!pq.isEmpty()) {
        long[] current = pq.poll();
        long currentCost = current[0];
        int i = current[1];
        int j = current[2];
        int t = current[3];

        // Check if we reached the destination
        if (i == m - 1 && j == n - 1) {
            return currentCost;
        }

        // Check if current cost is larger than the recorded distance
        if (currentCost > dist[i][j][t]) {
            continue;
        }

