import java.util.PriorityQueue;
import java.util.ArrayList;
import java.util.List;

public class Solution {
    public static long solve(long[][] grid, long k) {
        int m = grid.length;
        int n = grid[0].length;
        List<List<int[]>> teleport = new ArrayList<>();
        for (int i = 0; i < m; i++) {
            teleport.add(new ArrayList<>());
            for (int j = 0; j < n; j++) {
                List<int[]> list = new ArrayList<>();
                long val = grid[i][j];
                for (int x = 0; x < m; x++) {
                    for (int y = 0; y < n; y++) {
                        if (grid[x][y] <= val) {
                            list.add(new int[]{x, y});
                        }
                    }
                }
                teleport.get(i).add(list);
            }
        }

        long[][][] dist = new long[m][n][k + 1];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                for (int t = 0; t <= k; t++) {
                    dist[i][j][t] = Long.MAX_VALUE;
                }
            }
        }
        dist[0][0][0] = 0;

        PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
        pq.offer(new long[]{0, 0, 0, 0});

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long currentCost = current[0];
            int i = current[1];
            int j = current[2];
            int t = current[3];

            if (i == m - 1 && j == n - 1) {
                return currentCost;
            }

            if (currentCost > dist[i][j][t]) {
                continue;
            }

            if (j + 1 < n) {
                long newCost = currentCost + grid[i][j + 1];
                if (newCost < dist[i][j + 1][t]) {
                    dist[i][j + 1][t] = newCost;
                    pq.offer(new long[]{newCost, i, j + 1, t});
                }
            }

            if (i + 1 < m) {
                long newCost = currentCost + grid[i + 1][j];
                if (newCost < dist[i + 1][j][t]) {
                    dist[i + 1][j][t] = newCost;
                    pq.offer(new long[]{newCost, i + 1, j, t});
                }
            }

            if (t < k) {
                List<int[]> list = teleport.get(i).get(j);
                for (int[] coord : list) {
                    int x = coord[0];
                    int y = coord[1];
                    long newCost = currentCost;
                    if (newCost < dist[x][y][t + 1]) {
                        dist[x][y][t + 1] = newCost;
                        pq.offer(new long[]{newCost, x, y, t + 1});
                    }
                }
            }
        }

        return -1;
    }
}
